// Normalise data from either Telegram or Form trigger
const item = $input.first();
const data = item.json;

let machineType, siteName, durationDays, urgency, foremanName, foremanChatId;

// Detect source: Telegram has 'message' key, Form has 'formTitle'
if (data.message) {
  // Parse Telegram message: /breakdown [machine_type] | [site_name] | [duration_days]
  const text = data.message.text || '';
  const parts = text.replace('/breakdown', '').trim().split('|').map(s => s.trim());
  machineType = parts[0] || 'Unknown Machine';
  siteName = parts[1] || 'Unknown Site';
  durationDays = parseInt(parts[2]) || 1;
  urgency = 'Critical - Needed Today';
  foremanName = data.message.from?.first_name + ' ' + (data.message.from?.last_name || '');
  foremanChatId = String(data.message.chat?.id || '');
} else {
  // Form submission
  machineType = data['Machine Type'] || 'Unknown Machine';
  siteName = data['Site Name'] || 'Unknown Site';
  durationDays = parseInt(data['Duration Needed (Days)']) || 1;
  urgency = data['Urgency'] || 'Standard - Needed Within 48 Hours';
  foremanName = data['Foreman Name'] || 'Foreman';
  foremanChatId = data['Foreman Telegram Chat ID'] || '';
}

const breakdownId = 'BRK-' + Date.now();
const reportedAt = new Date().toISOString();

return [{
  json: {
    breakdownId,
    machineType,
    siteName,
    durationDays,
    urgency,
    foremanName,
    foremanChatId,
    reportedAt,
    vendorQuotes: [],
    source: data.message ? 'telegram' : 'form'
  }
}];

// Build individual vendor email payloads
// Replace these with your actual vendor emails and names
const vendors = [
  { name: 'Alpha Heavy Equipment Rentals', email: 'rentals@example-alpha.com' },
  { name: 'Beta Crane Hire Co.', email: 'hire@example-beta.com' },
  { name: 'Gamma Machinery Rentals', email: 'info@example-gamma.com' },
  { name: 'Delta Equipment Solutions', email: 'quotes@example-delta.com' },
  { name: 'Sigma Plant Hire', email: 'plant@example-sigma.com' }
];

const intake = $input.first().json;

return vendors.map(vendor => ({
  json: {
    ...intake,
    vendor
  }
}));

// Aggregate all vendor quotes collected during the wait period
// In production, quotes arrive via the webhook and are stored in a Google Sheet or memory
// This node reads them and compiles them for GPT-4o

const intake = $input.first().json;

// Sample structure - in production these come from webhook POSTs
// Replace with actual $json.body data from webhook
const collectedQuotes = intake.vendorQuotes && intake.vendorQuotes.length > 0
  ? intake.vendorQuotes
  : [
      // Fallback demo data structure if no real quotes yet
      { vendor: 'Alpha Heavy Equipment Rentals', available: true, dailyRate: 4500, deliveryHours: 4, notes: 'Includes operator, fuel extra' },
      { vendor: 'Beta Crane Hire Co.', available: true, dailyRate: 3900, deliveryHours: 6, notes: 'No operator, standard insurance' },
      { vendor: 'Gamma Machinery Rentals', available: false, dailyRate: null, deliveryHours: null, notes: 'Not available this week' }
    ];

const availableQuotes = collectedQuotes.filter(q => q.available !== false);

return [{
  json: {
    ...intake,
    collectedQuotes,
    availableQuotes,
    quotesCollectedAt: new Date().toISOString()
  }
}];

// Parse GPT-4o JSON response and merge with intake data
const item = $input.first();
const raw = item.json.message?.content || item.json.choices?.[0]?.message?.content || '';

let analysis;
try {
  const cleaned = raw.replace(/```json|```/g, '').trim();
  analysis = JSON.parse(cleaned);
} catch (e) {
  analysis = {
    comparisonTableHtml: '<p>Unable to parse vendor quotes.</p>',
    recommendedVendor: 'Manual Review Required',
    recommendedVendorRationale: raw,
    riskFlags: ['AI parsing error - please review manually'],
    executiveSummary: raw
  };
}

// Build approval URL (replace with your actual n8n webhook URL after deployment)
const approvalBaseUrl = 'https://YOUR-N8N-INSTANCE/webhook/approve-rental';
const approvalUrl = `${approvalBaseUrl}?id=${item.json.breakdownId}&vendor=${encodeURIComponent(analysis.recommendedVendor)}&approved=true`;
const rejectUrl = `${approvalBaseUrl}?id=${item.json.breakdownId}&approved=false`;

return [{
  json: {
    ...item.json,
    analysis,
    approvalUrl,
    rejectUrl
  }
}];

